480   OS << "Printing analysis 'Demanded Bits Analysis' for function '" << F.getName() << "':\n";
481   performAnalysis();
482   for (auto &KV : AliveBits) {
483     Instruction *I = KV.first;
484     PrintDB(I, KV.second);
